parsed.api_descriptions:
API_name: nchu_course_get_teacher_history
Description:
{
  "description": "Get a teacher's course history across all semesters. This searches all available semesters to find courses taught by the specified teacher. Note: This may be slow as it loads data from all semesters. JSON string containing teacher's course history grouped by semester",
  "required_parameters": [
    {
      "name": "teacher_name",
      "type": "STRING",
      "description": "Teacher name to search for"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit_per_semester",
      "type": "NUMBER",
      "description": "Maximum number of courses to show per semester (default: 10)",
      "default": 10
    }
  ]
}

